function checkSeatAvailability(arr)
{
  return new Promise((resolve, reject)=>
  {
    setTimeout(()=>
    {
      for(let obj of arr)
      {
        if(obj.seatsAvailable === 0 || obj.seatsRequested == null || obj.seatsAvailable == null)
        {
          reject("Rejected");
          return;
        }

        if(obj.seatsAvailable < obj.seatsRequested)
        {
          resolve("Partial");
          return;
        }
      }
      resolve("Available");

    },600);

  });
}

checkSeatAvailability([
  {seatsAvailable: 10, seatsRequested: 4 },
  {seatsAvailable: 3, seatsRequested: 7 }
])
.then(res=>console.log(res))
.catch(err=>console.log(err));